INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES
(201, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE5', 'Analisar a importância da diversidade genética, discutindo sua relação com organismos geneticamente modificados e transgênicos, considerando os princípios de biossegurança, bioética e biodiversidade.', NOW()),
(202, 'Ensino Fundamental: Anos Finais', 'Ciências', '6º Ano', NULL, 'AE1', 'Descrever as esferas que compõem a Terra, reconhecendo o surgimento da litosfera e suas transformações ao longo do tempo.', NOW()),
(203, 'Ensino Fundamental: Anos Finais', 'Ciências', '6º Ano', NULL, 'AE2', 'Explicar os efeitos dos movimentos do Sistema Terra-Sol-Lua na ocorrência de fenômenos naturais, considerando as relações entre rotação e translação da Terra e a interação entre Sol e Lua.', NOW()),
(204, 'Ensino Fundamental: Anos Finais', 'Ciências', '6º Ano', NULL, 'AE3', 'Classificar os tipos de rochas, identificando seus processos de formação e transformação do solo, como a fossilização em rochas sedimentares.', NOW()),
(205, 'Ensino Fundamental: Anos Finais', 'Ciências', '6º Ano', NULL, 'AE4', 'Analisar os processos de separação de misturas do cotidiano, classificando as substâncias, as misturas e as mudanças de estado físico da matéria.', NOW()),
(206, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE1', 'Investigar a teoria da deriva continental, relacionando a correspondência entre os formatos das costas brasileira e africana aos processos da tectônica de placas.', NOW()),
(207, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE2', 'Identificar a composição da atmosfera e os fatores naturais e humanos que a modificam, relacionando-os aos impactos ambientais e à saúde do sistema respiratório humano.', NOW()),
(208, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE3', 'Distinguir o uso e o funcionamento de máquinas simples, com base no conceito de força e exemplos do cotidiano.', NOW()),
(209, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE4', 'Aplicar os conceitos de calor, temperatura e sensação térmica na análise das formas de propagação do calor e do equilíbrio termodinâmico.', NOW()),
(210, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE5', 'Analisar os impactos econômicos, culturais e sociais das inovações tecnológicas na sociedade, destacando as máquinas elétricas e seu uso consciente.', NOW()),
(211, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE6', 'Analisar os impactos socioambientais do uso de combustíveis fósseis, das queimadas e do desmatamento, reconhecendo suas consequências para os ecossistemas.', NOW()),
(212, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE7', 'Identificar o efeito estufa como um fenômeno natural, reconhecendo os impactos das ações humanas que o intensificam.', NOW()),
(213, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE8', 'Explicar as características de vírus, bactérias e fungos, identificando as doenças que causam e as formas de preveni-las.', NOW()),
(214, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE9', 'Caracterizar os ecossistemas brasileiros, explicando como os fatores bióticos e abióticos se relacionam às características da fauna e da flora, considerando a biodiversidade como elemento central.', NOW()),
(215, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE1', 'Identificar as mudanças físicas e comportamentais que ocorrem na puberdade, relacionando-as às interações entre os sistemas nervoso e endócrino.', NOW()),
(216, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE2', 'Comparar processos reprodutivos assexuados e sexuados em vegetais e animais, com base em mecanismos evolutivos e adaptativos.', NOW()),
(217, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE3', 'Analisar formas de prevenção das infecções sexualmente transmissíveis e da gravidez precoce, reconhecendo práticas de saúde sexual e reprodutiva.', NOW()),
(218, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE4', 'Discutir os efeitos do uso de substâncias psicoativas para propor ações de prevenção voltadas à saúde individual e coletiva.', NOW()),
(219, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE5', 'Descrever as principais estruturas e funções do sistema digestório e dos nutrientes, relacionando-os à classificação dos alimentos em processados, ultraprocessados e in natura.', NOW()),
(220, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE6', 'Explicar o funcionamento do sistema respiratório e os fatores que comprometem sua atividade, incluindo a poluição atmosférica e as doenças.', NOW()),
(221, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE7', 'Explicar o funcionamento do sistema circulatório e sua relação com o sistema imune, reconhecendo ações que contribuem para a prevenção de doenças.', NOW()),
(222, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE1', 'Analisar a importância do acesso a informações científicas de qualidade, considerando os critérios de confiabilidade das fontes e avaliando os impactos da desinformação.', NOW()),
(223, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE2', 'Identificar os modelos que estruturam a matéria, reconhecendo a evolução histórica dos modelos atômicos e a classificação dos elementos químicos.', NOW()),
(224, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE3', 'Explicar as mudanças de estado físico, relacionando-as à estrutura molecular, aos estados de organização da matéria e às temperaturas de fusão e ebulição.', NOW()),
(225, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE4', 'Analisar as transformações químicas e as relações entre reagentes e produtos, aplicando as leis ponderais.', NOW()),
(226, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE5', 'Classificar as radiações eletromagnéticas de acordo com suas frequências e aplicações em diferentes tecnologias, reconhecendo suas implicações para a saúde e para o cotidiano.', NOW()),
(227, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE6', 'Investigar as características das ondas mecânicas e eletromagnéticas, reconhecendo como esses conhecimentos revolucionaram os sistemas de comunicação humana.', NOW()),
(228, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE7', 'Explicar os processos de hereditariedade e as aplicações da biotecnologia, articulando-os à genética clássica e à evolução biológica.', NOW()),
(229, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE8', 'Explicar a transmissão das características hereditárias com base nas ideias de Mendel sobre fatores hereditários, gametas, segregação e fecundação, utilizando heredogramas.', NOW()),
(230, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE9', 'Explicar as ideias evolucionistas de Lamarck e Darwin, destacando seus contextos históricos e sua relevância para a compreensão da biodiversidade.', NOW()),
(231, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE1', 'Analisar as origens da Filosofia, seus campos de investigação e as características da atitude filosófica, considerando a importância do diálogo e da argumentação fundamentada.', NOW()),
(232, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE2', 'Analisar a produção artística, compreendendo a formação do gosto e exercitando a atitude crítica diante de padrões estéticos, conhecimentos e valores historicamente construídos.', NOW()),
(233, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE3', 'Analisar as relações intergeracionais no Brasil e no mundo contemporâneo, problematizando estereótipos e a prática do etarismo, e reconhecendo a importância dos estatutos de proteção às diferentes fases da vida.', NOW()),
(234, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE4', 'Identificar formas de violência, suas causas e significados, avaliando mecanismos de enfrentamento com base em argumentos éticos.', NOW()),
(235, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE5', 'Analisar a formação do Estado e a legitimidade do poder político, aplicando o conceito de soberania a partir de pensadores do contratualismo, liberalismo e republicanismo clássicos.', NOW()),
(236, 'Ensino Médio', 'Física', '1ª Série', NULL, 'AE1', 'Resolver problemas envolvendo corpos em movimento com velocidade e/ou aceleração constantes, representando trajetória, posição, velocidade e aceleração por meio de funções, gráficos e tabelas.', NOW()),
(237, 'Ensino Médio', 'Física', '1ª Série', NULL, 'AE2', 'Analisar situações de equilíbrio e de movimento acelerado, aplicando grandezas escalares e vetoriais com operações algébricas e vetoriais, com base nas Leis de Newton.', NOW()),
(238, 'Ensino Médio', 'Física', '1ª Série', NULL, 'AE3', 'Aplicar os princípios de conservação da energia e da quantidade de movimento na análise de sistemas mecânicos que envolvem trabalho, potência, impulso e colisões.', NOW()),
(239, 'Ensino Médio', 'Física', '2ª Série', NULL, 'AE1', 'Interpretar sistemas térmicos, aplicando leis e modelos da Termodinâmica para descrever as transformações de energia associadas à transferência de calor e às variações de temperatura.', NOW()),
(240, 'Ensino Médio', 'Física', '2ª Série', NULL, 'AE2', 'Aplicar princípios da Termodinâmica na análise, avaliação e construção de sistemas térmicos, relacionando sua eficiência a contextos de uso sustentável da energia.', NOW()),
(241, 'Ensino Médio', 'Física', '3ª Série', NULL, 'AE1', 'Analisar interações eletrostáticas entre cargas e campos elétricos, calculando forças, potenciais e energia associada a situações práticas e simuladas.', NOW()),
(242, 'Ensino Médio', 'Física', '3ª Série', NULL, 'AE2', 'Analisar circuitos elétricos, calculando corrente, resistência, tensão, potência e consumo de energia.', NOW()),
(243, 'Ensino Médio', 'Química', '1ª Série', NULL, 'AE1', 'Analisar a evolução histórica e científica dos modelos atômicos, reconhecendo-os como uma construção humana e compreendendo como eles explicam fenômenos do cotidiano.', NOW()),
(244, 'Ensino Médio', 'Química', '1ª Série', NULL, 'AE2', 'Analisar a origem, a classificação e a organização dos elementos químicos na Tabela Periódica, reconhecendo as características dos radioisótopos e as leis das emissões radioativas.', NOW()),
(245, 'Ensino Médio', 'Química', '1ª Série', NULL, 'AE3', 'Analisar as diversas interações entre átomos, entre moléculas e entre átomos e moléculas, bem como seus efeitos nas propriedades dos materiais, distinguindo as ligações químicas e as interações intermoleculares das moléculas essenciais à vida.', NOW()),
(246, 'Ensino Médio', 'Química', '1ª Série', NULL, 'AE4', 'Analisar situações-problema em processos tecnológicos, produtivos, sustentáveis e ambientais, reconhecendo a quantidade de matéria e energia envolvidas nas transformações químicas.', NOW()),
(247, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE1', 'Analisar a composição, as propriedades e as aplicações dos metais pesados e dos plásticos para avaliar os impactos socioambientais e os riscos à saúde decorrentes de sua extração, produção e descarte inadequado.', NOW()),
(248, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE2', 'Analisar a eficiência e os impactos socioambientais dos combustíveis renováveis e não renováveis, calculando a entalpia das reações químicas e identificando a dependência mundial dos combustíveis não renováveis.', NOW()),
(249, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE3', 'Analisar os compostos orgânicos e as suas aplicações, nomeando, classificando e identificando as funções orgânicas, para elaborar ações de prevenção e de promoção da saúde e do bem-estar.', NOW()),
(250, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE4', 'Analisar caso de isomeria plana nos macro e micronutrientes, identificando as propriedades e as vantagens e desvantagens do uso dos compostos orgânicos na produção de alimentos.', NOW());
